const cfg = $('Config').first().json;
const DOMAIN = 'kurort-expert.ru';

const now = new Date();
const dd  = String(now.getDate()).padStart(2, '0');
const mm  = String(now.getMonth() + 1).padStart(2, '0');
const dateStr = `${dd}.${mm}`;

function colLetter(n) {
  let r = '';
  while (n > 0) {
    n--;
    r = String.fromCharCode(65 + (n % 26)) + r;
    n = Math.floor(n / 26);
  }
  return r;
}

const allRows   = $('Читаем ALL').all();
let allColCount = 2;
if (allRows.length > 0) {
  const keys = Object.keys(allRows[0].json).filter(k => !k.startsWith('__') && k !== 'row_number');
  allColCount = Math.max(keys.length, 2);
}
const mainYaCol = colLetter(allColCount + 1);
const mainGCol  = colLetter(allColCount + 2);

const yaRows   = $('Читаем Яндекс').all();
let yaColCount = 2;
if (yaRows.length > 0) {
  const keys = Object.keys(yaRows[0].json).filter(k => !k.startsWith('__') && k !== 'row_number');
  yaColCount = Math.max(keys.length, 2);
}
const yaNextCol = colLetter(yaColCount + 1);

const gRows   = $('Читаем Google').all();
let gColCount = 2;
if (gRows.length > 0) {
  const keys = Object.keys(gRows[0].json).filter(k => !k.startsWith('__') && k !== 'row_number');
  gColCount = Math.max(keys.length, 2);
}
const gNextCol = colLetter(gColCount + 1);

const isFirstRun = allRows.length === 0;

const inputRows = $('Читаем ключи').all();
const results   = [];

for (const item of inputRows) {
  const kw = (item.json['Ключевой запрос'] || '').trim();
  if (!kw) continue;
  if (kw === 'Ключевой запрос') continue;
  if (kw.includes('.рф')) continue;

  results.push({
    keyword:    kw,
    demand:     item.json['Спрос'] || '',
    rowNum:     item.json['row_number'],
    domain:     DOMAIN,
    dateStr,
    mainYaCol, mainGCol,
    yaNextCol,  gNextCol,
    isFirstRun,
    yaUrl: `https://xmlstock.com/yandex/xml/?user=${cfg.XMLSTOCK_USER}&key=${cfg.XMLSTOCK_KEY}&query=${encodeURIComponent(kw)}&lr=${cfg.YANDEX_REGION}&groupby=100`,
    gUrl:  `https://xmlstock.com/google/xml/?user=${cfg.XMLSTOCK_USER}&key=${cfg.XMLSTOCK_KEY}&query=${encodeURIComponent(kw)}&lr=ru&num=100&hl=ru`
  });
}

return results.map(r => ({ json: r }));

function parseXml(xmlStr, domain) {
  if (!xmlStr || typeof xmlStr !== 'string') return { pos: null, url: null };
  const docs = xmlStr.match(/<doc[\s\S]*?<\/doc>/g) || [];
  for (let j = 0; j < docs.length; j++) {
    const um = docs[j].match(/<url[^>]*>([^<]+)<\/url>/);
    if (um && um[1].toLowerCase().includes(domain.toLowerCase())) {
      return { pos: j + 1, url: um[1].trim() };
    }
  }
  return { pos: null, url: null };
}

const meta = $('Split').item.json;
const yaXml  = $('HTTP Яндекс').first().json.data || '';
const gXml   = $('HTTP Google').first().json.data || '';

const parsedY = parseXml(yaXml, meta.domain);
const parsedG = parseXml(gXml,  meta.domain);

return [{
  json: {
    keyword:    meta.keyword,
    demand:     meta.demand,
    rowNum:     meta.rowNum,
    domain:     meta.domain,
    dateStr:    meta.dateStr,
    mainYaCol:  meta.mainYaCol,
    mainGCol:   meta.mainGCol,
    yaNextCol:  meta.yaNextCol,
    gNextCol:   meta.gNextCol,
    isFirstRun: meta.isFirstRun,
    yPos: parsedY.pos,
    yUrl: parsedY.url,
    gPos: parsedG.pos,
    gUrl: parsedG.url,
  }
}];

const results = $input.all().map(i => i.json);
if (!results.length) return [];

const cfg = $('Config').first().json;
const sheet  = cfg.MAIN_SHEET;
const yaCol  = results[0].mainYaCol;
const gCol   = results[0].mainGCol;
const date   = results[0].dateStr;
const isFirst = results[0].isFirstRun;

const data = [];

if (isFirst) {
  data.push({ range: `${sheet}!A1`, values: [['Ключевой запрос']] });
  data.push({ range: `${sheet}!B1`, values: [['Спрос']] });
  for (const r of results) {
    data.push({ range: `${sheet}!A${r.rowNum}`, values: [[r.keyword]] });
    data.push({ range: `${sheet}!B${r.rowNum}`, values: [[r.demand]] });
  }
}

data.push({ range: `${sheet}!${yaCol}1`, values: [[`Я ${date}`]] });
data.push({ range: `${sheet}!${gCol}1`,  values: [[`G ${date}`]] });

for (const r of results) {
  const yVal = r.yPos
    ? `=HYPERLINK("${r.yUrl}";"${r.yPos}")`
    : '—';
  const gVal = r.gPos
    ? `=HYPERLINK("${r.gUrl}";"${r.gPos}")`
    : '—';
  data.push({ range: `${sheet}!${yaCol}${r.rowNum}`, values: [[yVal]] });
  data.push({ range: `${sheet}!${gCol}${r.rowNum}`,  values: [[gVal]] });
}

return [{ json: { body: { valueInputOption: 'USER_ENTERED', data } } }];

